mapper.select:
SELECT u.id, u.username, u.password, u.phone, u.company_id AS companyId, u.user_type AS userType, u.status, u.activator_id AS activatorId, u.last_login AS lastLogin, u.create_time AS createTime, ur.role_id AS roleId FROM app_user u LEFT JOIN app_user_role ur ON u.id = ur.user_id
u.company_id = #{companyId}
AND u.username LIKE concat('%', #{username}, '%')
AND u.phone LIKE concat('%', #{phone}, '%')
AND u.status = #{status}
AND ur.role_id = #{roleId}
AND u.create_time >= #{createTimeStart}
AND u.create_time <= #{createTimeEnd}
ORDER BY u.create_time DESC
